final:
module counter_2bit (
        input clk,
        input rst,
        output reg [1:0] count);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            count <= 2'b00;
        else
            count <= count + 1'b1;
    end

endmodule
